mapper.select:
SELECT 
FROM tpl_edit_lock
WHERE enterprise_id = #{enterpriseId}
  AND template_id   = #{templateId}
  AND audit_year    = #{auditYear}
  AND deleted = 0
LIMIT 1

mapper.update:
UPDATE tpl_edit_lock
SET deleted = 1, update_by = #{updateBy}, update_time = NOW()
WHERE enterprise_id = #{enterpriseId}
  AND template_id   = #{templateId}
  AND audit_year    = #{auditYear}
  AND deleted = 0
